def binary_search_recursive(arr, target):
    def _search(low, high):
        if low > high:
            return -1

        mid = low + (high - low) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            return _search(mid + 1, high)
        else:
            return _search(low, mid - 1)

    return _search(0, len(arr) - 1)


def binary_search_iterative(arr, target):
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = low + (high - low) // 2

        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1

    return -1
